oldWay:
/* Vertical centering in the float era */
.container {
  display: table-cell;
  vertical-align: middle;
  height: 200px;
}

/* Or the magic number approach */
.item {
  position: relative;
  top: 50%;
  transform: translateY(-50%);
}

startingCSS:
.container {
  display: flex;
  height: 160px;
  background: #1e293b;
  border-radius: 10px;
  padding: 1rem;
  gap: 1rem;
  border: 1px solid #334155;
}

.item {
  background: #a855f7;
  color: white;
  padding: 0.75rem 1.25rem;
  border-radius: 6px;
  font-weight: 500;
  font-size: 0.9rem;
}

.tall {
  background: #7c3aed;
  line-height: 1.6;
}

